import{_ as n,p as s,q as a,a1 as e}from"./framework-5866ffd3.js";const t={},p=e(`<h1 id="适配畸形接口" tabindex="-1"><a class="header-anchor" href="#适配畸形接口" aria-hidden="true">#</a> 适配畸形接口</h1><p>在实际应用场景中，常常会遇到一些设计不标准的畸形接口，主要是早期还没有restful概念时期的接口，我们要区分分析这些接口，包装为友好的客户端调用接口。</p><h2 id="不友好的参数名别名" tabindex="-1"><a class="header-anchor" href="#不友好的参数名别名" aria-hidden="true">#</a> 不友好的参数名别名</h2><p>例如服务器要求一个Query参数的名字为<code>field-Name</code>，这个是c#关键字或变量命名不允许的，我们可以使用<code>[AliasAsAttribute]</code>来达到这个要求：</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">public</span> <span class="token keyword">interface</span> <span class="token class-name">IDeformedApi</span>
<span class="token punctuation">{</span>
    <span class="token punctuation">[</span><span class="token attribute"><span class="token class-name">HttpGet</span><span class="token attribute-arguments"><span class="token punctuation">(</span><span class="token string">&quot;api/users&quot;</span><span class="token punctuation">)</span></span></span><span class="token punctuation">]</span>
    <span class="token return-type class-name">ITask<span class="token punctuation">&lt;</span><span class="token keyword">string</span><span class="token punctuation">&gt;</span></span> <span class="token function">GetAsync</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token attribute"><span class="token class-name">AliasAs</span><span class="token attribute-arguments"><span class="token punctuation">(</span><span class="token string">&quot;field-Name&quot;</span><span class="token punctuation">)</span></span></span><span class="token punctuation">]</span> <span class="token class-name"><span class="token keyword">string</span></span> fieldName<span class="token punctuation">)</span><span class="token punctuation">;</span>  
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>然后最终请求uri变为api/users/?field-name=<code>fileNameValue</code></p><h2 id="form的某个字段为json文本" tabindex="-1"><a class="header-anchor" href="#form的某个字段为json文本" aria-hidden="true">#</a> Form的某个字段为json文本</h2><table><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td>field1</td><td>someValue</td></tr><tr><td>field2</td><td>{&quot;name&quot;:&quot;sb&quot;,&quot;age&quot;:18}</td></tr></tbody></table><p>对应强类型模型是</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">class</span> <span class="token class-name">Field2</span>
<span class="token punctuation">{</span>
    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">string</span></span> Name <span class="token punctuation">{</span><span class="token keyword">get</span><span class="token punctuation">;</span> <span class="token keyword">set</span><span class="token punctuation">;</span><span class="token punctuation">}</span>
    
    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">int</span></span> Age <span class="token punctuation">{</span><span class="token keyword">get</span><span class="token punctuation">;</span> <span class="token keyword">set</span><span class="token punctuation">;</span><span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>常规下我们得把field2的实例json序列化得到json文本，然后赋值给field2这个string属性，使用[JsonFormField]特性可以轻松帮我们自动完成Field2类型的json序列化并将结果字符串作为表单的一个字段。</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">public</span> <span class="token keyword">interface</span> <span class="token class-name">IDeformedApi</span>
<span class="token punctuation">{</span>
    <span class="token return-type class-name">Task</span> <span class="token function">PostAsync</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token attribute"><span class="token class-name">FormField</span></span><span class="token punctuation">]</span> <span class="token class-name"><span class="token keyword">string</span></span> field1<span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token attribute"><span class="token class-name">JsonFormField</span></span><span class="token punctuation">]</span> <span class="token class-name">Field2</span> field2<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="form提交嵌套的模型" tabindex="-1"><a class="header-anchor" href="#form提交嵌套的模型" aria-hidden="true">#</a> Form提交嵌套的模型</h2><table><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td>filed1</td><td>someValue</td></tr><tr><td>field2.name</td><td>sb</td></tr><tr><td>field2.age</td><td>18</td></tr></tbody></table><p>其对应的json格式为</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">{</span>
    <span class="token property">&quot;field1&quot;</span> <span class="token operator">:</span> <span class="token string">&quot;someValue&quot;</span><span class="token punctuation">,</span>
    <span class="token property">&quot;filed2&quot;</span> <span class="token operator">:</span> <span class="token punctuation">{</span>
        <span class="token property">&quot;name&quot;</span> <span class="token operator">:</span> <span class="token string">&quot;sb&quot;</span><span class="token punctuation">,</span>
        <span class="token property">&quot;age&quot;</span> <span class="token operator">:</span> <span class="token number">18</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>合理情况下，对于复杂嵌套结构的数据模型，应当使用applicaiton/json，但接口要求必须使用Form提交，我可以配置KeyValueSerializeOptions来达到这个格式要求：</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code>services<span class="token punctuation">.</span><span class="token generic-method"><span class="token function">AddHttpApi</span><span class="token generic class-name"><span class="token punctuation">&lt;</span>IDeformedApi<span class="token punctuation">&gt;</span></span></span><span class="token punctuation">(</span>o <span class="token operator">=&gt;</span>
<span class="token punctuation">{</span>
    o<span class="token punctuation">.</span>KeyValueSerializeOptions<span class="token punctuation">.</span>KeyNamingStyle <span class="token operator">=</span> KeyNamingStyle<span class="token punctuation">.</span>FullName<span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="响应未指明contenttype" tabindex="-1"><a class="header-anchor" href="#响应未指明contenttype" aria-hidden="true">#</a> 响应未指明ContentType</h2><p>明明响应的内容肉眼看上是json内容，但服务响应头里没有ContentType告诉客户端这内容是json，这好比客户端使用Form或json提交时就不在请求头告诉服务器内容格式是什么，而是让服务器猜测一样的道理。</p><p>解决办法是在Interface或Method声明<code>[JsonReturn]</code>特性，并设置其EnsureMatchAcceptContentType属性为false，表示ContentType不是期望值匹配也要处理。</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token punctuation">[</span><span class="token attribute"><span class="token class-name">JsonReturn</span><span class="token attribute-arguments"><span class="token punctuation">(</span>EnsureMatchAcceptContentType <span class="token operator">=</span> <span class="token boolean">false</span><span class="token punctuation">)</span></span></span><span class="token punctuation">]</span> 
<span class="token keyword">public</span> <span class="token keyword">interface</span> <span class="token class-name">IDeformedApi</span> 
<span class="token punctuation">{</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="类签名参数或apikey参数" tabindex="-1"><a class="header-anchor" href="#类签名参数或apikey参数" aria-hidden="true">#</a> 类签名参数或apikey参数</h2><p>例如每个请求的url额外的动态添加一个叫sign的参数，这个sign可能和请求参数值有关联，每次都需要计算。</p><p>我们可以自定义ApiFilterAttribute来实现自己的sign功能，然后把自定义Filter声明到Interface或Method即可</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">class</span> <span class="token class-name">SignFilterAttribute</span> <span class="token punctuation">:</span> <span class="token type-list"><span class="token class-name">ApiFilterAttribute</span></span>
<span class="token punctuation">{</span>
    <span class="token keyword">public</span> <span class="token keyword">override</span> <span class="token return-type class-name">Task</span> <span class="token function">OnRequestAsync</span><span class="token punctuation">(</span><span class="token class-name">ApiRequestContext</span> context<span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token class-name"><span class="token keyword">var</span></span> signService <span class="token operator">=</span> context<span class="token punctuation">.</span>HttpContext<span class="token punctuation">.</span>ServiceProvider<span class="token punctuation">.</span><span class="token generic-method"><span class="token function">GetService</span><span class="token generic class-name"><span class="token punctuation">&lt;</span>SignService<span class="token punctuation">&gt;</span></span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token class-name"><span class="token keyword">var</span></span> sign <span class="token operator">=</span> signService<span class="token punctuation">.</span><span class="token function">SignValue</span><span class="token punctuation">(</span>DateTime<span class="token punctuation">.</span>Now<span class="token punctuation">)</span><span class="token punctuation">;</span>
        context<span class="token punctuation">.</span>HttpContext<span class="token punctuation">.</span>RequestMessage<span class="token punctuation">.</span><span class="token function">AddUrlQuery</span><span class="token punctuation">(</span><span class="token string">&quot;sign&quot;</span><span class="token punctuation">,</span> sign<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">return</span> Task<span class="token punctuation">.</span>CompletedTask<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

<span class="token punctuation">[</span><span class="token attribute"><span class="token class-name">SignFilter</span></span><span class="token punctuation">]</span>
<span class="token keyword">public</span> <span class="token keyword">interface</span> <span class="token class-name">IDeformedApi</span> 
<span class="token punctuation">{</span>
    <span class="token range operator">..</span><span class="token punctuation">.</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="表单字段排序" tabindex="-1"><a class="header-anchor" href="#表单字段排序" aria-hidden="true">#</a> 表单字段排序</h2><p>不知道是哪门公司起的所谓的“签名算法”，往往要字段排序等。</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">class</span> <span class="token class-name">SortedFormContentAttribute</span> <span class="token punctuation">:</span> <span class="token type-list"><span class="token class-name">FormContentAttribute</span></span>
<span class="token punctuation">{</span>
    <span class="token keyword">protected</span> <span class="token keyword">override</span> <span class="token return-type class-name">IEnumerable<span class="token punctuation">&lt;</span>KeyValue<span class="token punctuation">&gt;</span></span> <span class="token function">SerializeToKeyValues</span><span class="token punctuation">(</span><span class="token class-name">ApiParameterContext</span> context<span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        这里可以排序、加上其它衍生字段等
        <span class="token keyword">return</span> <span class="token keyword">base</span><span class="token punctuation">.</span><span class="token function">SerializeToKeyValues</span><span class="token punctuation">(</span>context<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">OrderBy</span><span class="token punctuation">(</span>item <span class="token operator">=&gt;</span> item<span class="token punctuation">.</span>Key<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

<span class="token keyword">public</span> <span class="token keyword">interface</span> <span class="token class-name">IDeformedApi</span>
<span class="token punctuation">{</span>
    <span class="token punctuation">[</span><span class="token attribute"><span class="token class-name">HttpGet</span><span class="token attribute-arguments"><span class="token punctuation">(</span><span class="token string">&quot;/path&quot;</span><span class="token punctuation">)</span></span></span><span class="token punctuation">]</span>
    <span class="token return-type class-name">Task<span class="token punctuation">&lt;</span>HttpResponseMessage<span class="token punctuation">&gt;</span></span> <span class="token function">PostAsync</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token attribute"><span class="token class-name">SortedFormContent</span></span><span class="token punctuation">]</span> <span class="token class-name">Model</span> model<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,29),c=[p];function o(i,l){return s(),a("div",null,c)}const r=n(t,[["render",o],["__file","deformed-interface.html.vue"]]);export{r as default};
